async setCookieConsent(dto: CookieConsentDto, req: Request): Promise<void> {
  const sessionId = req.cookies['sessionId'] || this.generateSessionId();
  const userId = req.user?.id || null;

  // Enregistrer le consentement en base
  const consent = this.consentRepository.create({
    userId,
    sessionId,
    preferences: {
      necessary: true,
      analytics: dto.analytics || false,
      marketing: dto.marketing || false,
      functional: dto.functional || false,
    },
    consentedAt: new Date(),
    ipAddress: req.ip,
    userAgent: req.headers['user-agent'],
    expiresAt: new Date(Date.now() + 6 * 30 * 24 * 60 * 60 * 1000),
  });

  await this.consentRepository.save(consent);

  // Définir un cookie de consentement (pour ne pas redemander à chaque visite)
  res.cookie('cookie_consent', {
    analytics: dto.analytics,
    marketing: dto.marketing,
    functional: dto.functional,
  }, {
    httpOnly: true,
    secure: process.env.NODE_ENV === 'production',
    sameSite: 'lax',
    maxAge: 6 * 30 * 24 * 60 * 60 * 1000,
  });

  // Initialiser ou mettre à jour les cookies de suivi selon consentement
  if (dto.analytics) {
    this.initializeAnalyticsCookies(res);
  } else {
    this.blockAnalyticsCookies(res);
  }
}
