// Transaction de suppression
async deleteUserData(userId: string): Promise<void> {
  const queryRunner = this.dataSource.createQueryRunner();
  await queryRunner.startTransaction();

  try {
    // 1. Anonymiser les commandes
    await queryRunner.manager.update(Order, { userId }, { userId: null });

    // 2. Anonymiser les avis
    await queryRunner.manager.update(Review, { userId }, { userId: null });

    // 3. Anonymiser les paiements
    await queryRunner.manager.update(Payment, { userId }, { userId: null });

    // 4. Supprimer les entités personnelles
    await queryRunner.manager.delete(Wishlist, { userId });
    await queryRunner.manager.delete(Cart, { userId });
    await queryRunner.manager.delete(Address, { userId });
    await queryRunner.manager.delete(CookieConsent, { userId });

    // 5. Supprimer l'utilisateur
    await queryRunner.manager.delete(User, { id: userId });

    await queryRunner.commitTransaction();
  } catch (error) {
    await queryRunner.rollbackTransaction();
    throw error;
  } finally {
    await queryRunner.release();
  }
}
