async exportUserData(userId: string): Promise<UserExportDto> {
  const user = await this.userRepository.findOne({
    where: { id: userId },
    relations: ['addresses', 'orders', 'reviews', 'wishlist'],
  });

  if (!user) {
    throw new NotFoundException('Utilisateur non trouvé');
  }

  // Exclure les données sensibles
  const { password, ...safeUser } = user;

  // Formater les commandes
  const orders = await this.orderRepository.find({
    where: { userId },
    relations: ['items'],
  });

  // Exporter les avis
  const reviews = await this.reviewRepository.find({
    where: { userId },
  });

  const exportData: UserExportDto = {
    user: safeUser,
    createdAt: user.createdAt,
    exportDate: new Date(),
    addresses: user.addresses,
    orders: orders.map(order => ({
      id: order.id,
      date: order.createdAt,
      total: order.total,
      status: order.status,
      items: order.items,
    })),
    reviews: reviews.map(review => ({
      productId: review.productId,
      rating: review.rating,
      comment: review.comment,
      date: review.createdAt,
    })),
    wishlist: user.wishlist,
  };

  // Générer un fichier et le stocker temporairement
  const jsonContent = JSON.stringify(exportData, null, 2);
  const filename = `export_user_${userId}_${Date.now()}.json`;
  const filepath = path.join('/tmp', filename);
  await fs.promises.writeFile(filepath, jsonContent, 'utf-8');

  // Upload vers S3 avec URL temporaire (24h)
  const fileUrl = await this.storageService.upload(
    `exports/${filename}`,
    filepath,
    { expiresIn: 86400 }
  );

  // Nettoyage
  setTimeout(() => fs.promises.unlink(filepath).catch(() => {}), 3600000);

  return { downloadUrl: fileUrl, expiresAt: new Date(Date.now() + 86400000) };
}
